INSERT INTO `pertanyaan_survei` VALUES ('019f3b90-17fb-7285-a601-02f63720c6bb',1,'Pegawai memberikan pelayanan yang ramah, cepat, responsif, dan berorientasi pada kebutuhan pengguna layanan.','Berorientasi Pelayanan',1.00,'2026-07-07 00:52:06','2026-07-07 00:52:06'),('019f3b90-180e-72ff-97e3-f2c5bffdb3c5',2,'Pegawai melaksanakan tugas secara jujur, bertanggung jawab, dan dapat dipertanggungjawabkan.','Akuntabel',1.00,'2026-07-07 00:52:06','2026-07-07 00:52:06'),('019f3b90-1813-7041-802b-cf915b905400',3,'Pegawai memiliki pengetahuan dan kemampuan yang memadai dalam menjalankan tugas serta memberikan pelayanan.','Kompeten',1.00,'2026-07-07 00:52:06','2026-07-07 00:52:06'),('019f3b90-181b-72bd-9cf9-22ab28ae4c6a',4,'Pegawai bersikap sopan, menghargai orang lain, serta mampu menjaga hubungan kerja yang baik.','Harmonis',1.00,'2026-07-07 00:52:06','2026-07-07 00:52:06'),('019f3b90-1820-71d2-9768-4cbebaad7296',5,'Pegawai menunjukkan komitmen, integritas, dan loyalitas terhadap organisasi serta melaksanakan tugas sesuai ketentuan.','Loyal',1.00,'2026-07-07 00:52:06','2026-07-07 00:52:06'),('019f3b90-1826-72ed-a616-37c75e842d55',6,'Pegawai mampu menyesuaikan diri dengan perubahan, menerima masukan, dan terbuka terhadap inovasi.','Adaptif',1.00,'2026-07-07 00:52:06','2026-07-07 00:52:06'),('019f3b90-182c-72a6-9fd2-819ae5541d12',7,'Pegawai mampu bekerja sama dengan rekan kerja maupun pihak lain untuk mencapai tujuan bersama.','Kolaboratif',1.00,'2026-07-07 00:52:06','2026-07-07 00:52:06');
